import math
class Solution:
    def areConnected(self, n, threshold, queries):
        adj = [[] for _ in range(n + 1)]
        for x in range(1, n + 1):
            for y in range(x + 1, n + 1):
                if math.gcd(x, y) > threshold:
                    adj[x].append(y)
                    adj[y].append(x)
        comp = [0] * (n + 1)
        c = 0
        for i in range(1, n + 1):
            if comp[i] == 0:
                c += 1
                stack = [i]
                comp[i] = c
                while stack:
                    u = stack.pop()
                    for v in adj[u]:
                        if comp[v] == 0:
                            comp[v] = c
                            stack.append(v)
        return [comp[a] == comp[b] for a, b in queries]

