class Solution:
    def areConnected(self, n, threshold, queries):
        parent = list(range(n + 1))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
        for z in range(threshold + 1, n + 1):
            for multiple in range(2 * z, n + 1, z):
                union(z, multiple)
        return [find(a) == find(b) for a, b in queries]

